import React from "react";
import { Link } from "react-router-dom";
import ReactPlayer from "react-player";

import data from "../../../data.json";

class Grid extends React.Component {
  render() {
    return (
      <div>
        {data.Projects.map((projects, i) => {
          return (
            <div key={i}>
              <h1>{projects.description}</h1>
              <Link to={projects.url}>
                <img src={projects.img} alt={"img"} width={"100%"} />
              </Link>
              <ReactPlayer
                playing="true"
                loop="true"
                muted="false"
                width="100%"
                url="https://storage.googleapis.com/spec-host-backup/mio-components%2Fassets%2F1qIHOMquJE7flVh1ttDTSogXdvEX2lY_1%2F01-list-parentchild.mp4"
              />
            </div>
          );
        })}
      </div>
    );
  }
}

export default Grid;
